import React, { useState, useEffect } from 'react';
import { ethers } from 'ethers';
import VotingContract from './Voting.json';

const VotingApp = () => {
    const [provider, setProvider] = useState(null);
    const [contract, setContract] = useState(null);
    const [candidates, setCandidates] = useState([]);
    const [hasVoted, setHasVoted] = useState(false);
    const contractAddress = "YOUR_CONTRACT_ADDRESS";

    useEffect(() => {
        const init = async () => {
            if (window.ethereum) {
                const newProvider = new ethers.providers.Web3Provider(window.ethereum);
                const signer = newProvider.getSigner();
                const newContract = new ethers.Contract(contractAddress, VotingContract.abi, signer);
                setProvider(newProvider);
                setContract(newContract);
            } else {
                alert("Please install MetaMask!");
            }
        };
        init();
    }, []);

    const loadCandidates = async () => {
        const count = await contract.candidatesCount();
        const loadedCandidates = [];
        for (let i = 1; i <= count; i++) {
            const candidate = await contract.candidates(i);
            loadedCandidates.push({ id: candidate.id, name: candidate.name, votes: candidate.voteCount });
        }
        setCandidates(loadedCandidates);
    };

    const vote = async (id) => {
        if (contract) {
            try {
                await contract.vote(id);
                setHasVoted(true);
                loadCandidates(); // Update the candidates' votes
            } catch (error) {
                console.error("Voting failed", error);
            }
        }
    };

    useEffect(() => {
        if (contract) loadCandidates();
    }, [contract]);

    return (
        <div>
            <h1>Decentralized Voting Platform</h1>
            <ul>
                {candidates.map((candidate) => (
                    <li key={candidate.id}>
                        {candidate.name} - {candidate.votes} votes
                        <button onClick={() => vote(candidate.id)} disabled={hasVoted}>
                            Vote
                        </button>
                    </li>
                ))}
            </ul>
        </div>
    );
};

export default VotingApp;
